import json

try:
    raw_str = ${{kafka_consumer_trigger | tojson | tojson}}
    data = json.loads(raw_str)

    columns = data.get('columns')
    if not columns or not isinstance(columns, dict):
        print(json.dumps({"__error__": "Missing or invalid 'columns' field in request."}))
    else:
        available_classifications = data.get('availableClassifications', [])
        classification_rules = data.get('classificationRules', [])
        confidence_threshold = data.get('confidenceThreshold', 0.85)

        column_classification = columns.get('classificationType', '')
        relevant_rules = []
        for r in classification_rules:
            if r.get('classificationType') == column_classification and r.get('enabled', True):
                relevant_rules.append(r)

        raw_samples = columns.get('sampleValues', [])
        safe_samples = []
        for sv in raw_samples[:5]:
            s = str(sv) if not isinstance(sv, str) else sv
            safe_samples.append(s[:200] + '...' if len(s) > 200 else s)

        context = {
            "column": {
                "columnId": columns.get('columnId'),
                "columnName": columns.get('columnName'),
                "tableName": columns.get('tableName'),
                "schemaName": columns.get('schemaName'),
                "columnType": columns.get('columnType'),
                "classificationType": columns.get('classificationType'),
                "classificationStatus": columns.get('classificationStatus'),
                "classificationRatio": columns.get('classificationRatio'),
                "sampleValues": safe_samples
            },
            "availableClassifications": available_classifications,
            "relevantRules": relevant_rules,
            "confidenceThreshold": confidence_threshold
        }
        print(json.dumps(context, ensure_ascii=False, indent=2))

except Exception as e:
    error_payload = {
        "requestId": data.get("requestId", "unknown") if 'data' in locals() and isinstance(data, dict) else "unknown",
        "pipelineId": data.get("pipelineId", "unknown") if 'data' in locals() and isinstance(data, dict) else "unknown",
        "status": "FAILED",
        "error_details": {
            "error_type": type(e).__name__,
            "message": str(e)
        },
        "classificationStatus": "FAILED_SYSTEM_ERROR"
    }
    print(json.dumps(error_payload, ensure_ascii=False))

