import json

try:
    raw_str = ${{kafka_consumer_trigger | tojson | tojson}}
    data = json.loads(raw_str)

    request_id = data['requestId']
    column_id = data['columns']['columnId']
    confidence_threshold = float(data.get('confidenceThreshold', 0.85))

    ai_response_raw = node_data if isinstance(node_data, str) else (str(node_data) if node_data is not None else "")
    error_message = None

    # 1. Detect structured FAILED response from agent
    agent_failed = False
    try:
        _agent_dict = json.loads(ai_response_raw)
        if isinstance(_agent_dict, dict) and _agent_dict.get('status') == 'FAILED':
            agent_failed = True
            error_message = (_agent_dict.get('error_details') or {}).get('message', 'Agent execution failed.')
    except json.JSONDecodeError:
        pass

    # 2. Legacy error string detection
    if agent_failed or not ai_response_raw or 'execution failed' in ai_response_raw or ai_response_raw.startswith('Error'):
        if not error_message:
            error_message = ai_response_raw[:500] if ai_response_raw else 'Agent returned no response.'
        result_data = {
            "columnId": column_id,
            "suggestedAction": "MANUAL_REVIEW",
            "confidence": 0.0,
            "reason": None,
            "suggestedClassificationType": None,
            "error": error_message
        }
    else:
        # 3. Clean and parse JSON response
        clean_response = ai_response_raw.strip('` \n')
        if clean_response.lower().startswith('json'):
            clean_response = clean_response[4:].strip()

        result_data = None
        if clean_response and clean_response[0] in ('{', '['):
            try:
                parsed = json.loads(clean_response)
                result_data = parsed[0] if isinstance(parsed, list) else parsed
            except json.JSONDecodeError as parse_err:
                error_message = 'JSON parse error: ' + str(parse_err) + ' | Raw: ' + clean_response[:300]

        if result_data is None:
            result_data = {
                "columnId": column_id,
                "suggestedAction": "MANUAL_REVIEW",
                "confidence": 0.0,
                "reason": None,
                "suggestedClassificationType": None,
                "error": error_message if error_message else 'Agent returned non-JSON response: ' + ai_response_raw[:300]
            }

    # 4. Ensure columnId is always present
    result_data.setdefault('columnId', column_id)

    # 5. Normalize suggestedClassificationType
    if result_data.get('suggestedClassificationType'):
        result_data['suggestedClassificationType'] = result_data['suggestedClassificationType'].strip()

    # 6. Confidence threshold: downgrade to MANUAL_REVIEW if below threshold
    ai_confidence = float(result_data.get('confidence') or 0.0)
    if result_data.get('suggestedAction') not in ('MANUAL_REVIEW', 'IGNORE') and ai_confidence < confidence_threshold:
        result_data['suggestedAction'] = 'MANUAL_REVIEW'

    # 7. REVIEW path: enforce business rules
    action = result_data.get('suggestedAction')
    if action in ('CONFIRM', 'FALSE_POSITIVE', 'IGNORE'):
        # SAFE → no classification assigned
        result_data['suggestedClassificationType'] = None
    # OVERRIDE → SENSITIVE, classification changes (keep suggestedClassificationType)

    print(json.dumps({'requestId': request_id, 'result': result_data}))

except Exception as e:
    error_payload = {
        "requestId": data.get("requestId", "unknown") if 'data' in locals() and isinstance(data, dict) else "unknown",
        "pipelineId": data.get("pipelineId", "unknown") if 'data' in locals() and isinstance(data, dict) else "unknown",
        "status": "FAILED",
        "error_details": {
            "error_type": type(e).__name__,
            "message": str(e)
        },
        "classificationStatus": "FAILED_SYSTEM_ERROR"
    }
    print(json.dumps(error_payload, ensure_ascii=False))

