import json

try:
    raw_str = ${{kafka_consumer_trigger | tojson | tojson}}
    data = json.loads(raw_str)
    request_id = data.get('requestId', '')
    column_id = data.get('columns', {}).get('columnId', '')

    ctx_str = ${{code_node_context | tojson | tojson}}
    context_out = json.loads(ctx_str)
    if not isinstance(context_out, dict):
        context_out = {}

    if '__error__' in context_out:
        error_msg = context_out['__error__']
    elif context_out.get('status') == 'FAILED':
        error_msg = (context_out.get('error_details') or {}).get('message', 'Upstream node failed.')
    else:
        error_msg = 'Classification status not supported or an unexpected error occurred.'

    output = {
        "requestId": request_id,
        "result": {
            "columnId": column_id,
            "suggestedAction": "MANUAL_REVIEW",
            "suggestedClassificationType": None,
            "confidence": 0.0,
            "reason": "Automatic classification failed. Manual review required. Error: " + str(error_msg)[:300],
            "error": error_msg
        }
    }
    print(json.dumps(output))

except Exception as e:
    fallback = {
        "requestId": data.get('requestId', 'unknown') if 'data' in locals() and isinstance(data, dict) else 'unknown',
        "result": {
            "columnId": data.get('columns', {}).get('columnId', 'unknown') if 'data' in locals() and isinstance(data, dict) else 'unknown',
            "suggestedAction": "MANUAL_REVIEW",
            "suggestedClassificationType": None,
            "confidence": 0.0,
            "reason": "System error during processing. Manual review required.",
            "error": type(e).__name__ + ": " + str(e)
        }
    }
    print(json.dumps(fallback, ensure_ascii=False))
